import torch
import torch.nn as nn

try:
    from fla.layers import GatedLinearAttention
    FLA_AVAILABLE = True
except ImportError:
    print("Warning: 'flash-linear-attention' package not found. GLA model will not be available.")
    FLA_AVAILABLE = False

# This script provides a minimal example of replacing a standard attention
# mechanism with GatedLinearAttention (GLA) from the flash-linear-attention library.
# This is a proof-of-concept for integrating efficient attention into a VLM
# architecture for fine-tuning on long-context data generated by VQASynth.

class VlmBlock(nn.Module):
    """
    A simplified VLM block to demonstrate attention layer swapping.
    In a real VLM, this would be part of a larger transformer architecture
    and handle both vision and language embeddings.
    """
    def __init__(self, d_model=1024, n_head=16, use_gla=False):
        super().__init__()
        self.d_model = d_model
        self.n_head = n_head
        self.use_gla = use_gla

        self.norm = nn.LayerNorm(d_model)

        if self.use_gla:
            if not FLA_AVAILABLE:
                raise ImportError("GatedLinearAttention requires the 'flash-linear-attention' package.")
            # Using Gated Linear Attention from flash-linear-attention
            # This is a sub-quadratic attention mechanism, efficient for long sequences.
            print("Using GatedLinearAttention (GLA)")
            self.attn = GatedLinearAttention(
                d_model=d_model,
                num_heads=n_head
            )
        else:
            # Using PyTorch's standard MultiheadAttention
            # This has quadratic complexity w.r.t sequence length.
            print("Using standard MultiheadAttention")
            self.attn = nn.MultiheadAttention(
                embed_dim=d_model,
                num_heads=n_head,
                batch_first=True
            )

        self.ffn = nn.Sequential(
            nn.Linear(d_model, d_model * 4),
            nn.GELU(),
            nn.Linear(d_model * 4, d_model)
        )

    def forward(self, x):
        # x: (batch_size, seq_len, d_model)
        x_norm = self.norm(x)

        if self.use_gla:
            # GatedLinearAttention from fla handles the (batch, seq_len, d_model) format directly
            attn_output, _ = self.attn(x_norm)
        else:
            # Standard attention returns (output, weights)
            attn_output, _ = self.attn(x_norm, x_norm, x_norm, need_weights=False)

        # Residual connections
        x = x + attn_output
        x = x + self.ffn(self.norm(x))
        return x

def run_test():
    """
    Instantiates both model versions and runs a dummy forward pass.
    """
    if not torch.cuda.is_available():
        raise RuntimeError("This experiment requires a CUDA-enabled GPU.")

    batch_size = 4
    seq_len = 2048  # A sequence length where efficiency starts to matter
    d_model = 512
    n_head = 8

    # Dummy input tensor
    dummy_input = torch.randn(batch_size, seq_len, d_model).cuda()

    print("-" * 50)
    # Test 1: Standard Attention
    try:
        model_standard = VlmBlock(d_model, n_head, use_gla=False).cuda()
        output_standard = model_standard(dummy_input)
        print(f"Standard Attention model forward pass successful.")
        print(f"Output shape: {output_standard.shape}")
        del model_standard, output_standard
        torch.cuda.empty_cache()
    except Exception as e:
        print(f"Standard Attention model failed: {e}")

    print("-" * 50)
    # Test 2: Gated Linear Attention (GLA)
    if FLA_AVAILABLE:
        try:
            model_gla = VlmBlock(d_model, n_head, use_gla=True).cuda()
            output_gla = model_gla(dummy_input)
            print(f"Gated Linear Attention (GLA) model forward pass successful.")
            print(f"Output shape: {output_gla.shape}")
            del model_gla, output_gla
            torch.cuda.empty_cache()
        except Exception as e:
            print(f"GLA model failed: {e}")
            print("This might be due to a CUDA/Triton version incompatibility.")
    else:
        print("Skipping GLA model test because 'flash-linear-attention' is not installed.")
    print("-" * 50)

if __name__ == "__main__":
    run_test()
